class Solution:
    def numSpecialEquivGroups(self, words):
        """
        :type words: List[str]
        :rtype: int
        """
        def get_signature(word):
            # Count chars at even and odd indices separately
            even_chars = sorted([word[i] for i in range(0, len(word), 2)])
            odd_chars = sorted([word[i] for i in range(1, len(word), 2)])
            return (tuple(even_chars), tuple(odd_chars))

        signatures = set()
        for word in words:
            signatures.add(get_signature(word))

        return len(signatures)
